const items = $input.all();
const results = [];

for (const item of items) {
  const responseText = item.json.choices?.[0]?.message?.content || '';
  const cleanText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let scores;
  try {
    scores = JSON.parse(cleanText);
  } catch (e) {
    const match = cleanText.match(/\{[\s\S]*?\}/);
    if (match) {
      scores = JSON.parse(match[0]);
    } else {
      scores = { branche: 'FEHLER', neukunden_score: 0, erreichbarkeit_score: 0, inhaberquote_score: 0, maps_wettbewerb_score: 0 };
    }
  }

  const n = Number(scores.neukunden_score) || 0;
  const e = Number(scores.erreichbarkeit_score) || 0;
  const i = Number(scores.inhaberquote_score) || 0;
  const m = Number(scores.maps_wettbewerb_score) || 0;
  const gesamt = Math.round(((n*4 + e*4 + i*3 + m*3) / 14) * 10) / 10;

  results.push({
    json: {
      branche: scores.branche || '',
      neukunden_score: n,
      erreichbarkeit_score: e,
      inhaberquote_score: i,
      maps_wettbewerb_score: m,
      gesamt_score: gesamt
    }
  });
}

return results;
